import os, re, sys

def check_file(path):
    with open(path) as f:
        lines = f.readlines()
    undoc = []
    for i, line in enumerate(lines):
        stripped = line.strip()
        if re.match(r'pub\s', stripped) and not re.match(r'pub\s+(use|mod|type)\s', stripped):
            # look back up to 3 lines for ///
            start = max(0, i-3)
            preceding = lines[start:i]
            if not any(l.strip().startswith('///') for l in preceding):
                undoc.append((path, i+1, stripped[:80]))
    return undoc

problems = []
for root, dirs, files in os.walk('src'):
    dirs[:] = [d for d in dirs if not d.startswith('.')]
    for f in files:
        if f.endswith('.rs'):
            problems.extend(check_file(os.path.join(root, f)))

if problems:
    print(f'FAIL: {len(problems)} undocumented pub items:')
    for p, lineno, text in problems:
        print(f'  {p}:{lineno}: {text}')
    sys.exit(1)
else:
    print(f'PASS: 0 undocumented pub items in src/')
